import{some}from"@hyperjump/pact";import*as Instance from"../lib/instance.js";import Validation from"../lib/keywords/validation.js";const id="https://json-schema.org/keyword/draft-06/contains",compile=(t,i)=>Validation.compile(t,i),interpret=(i,t,e,o,r)=>!Instance.typeOf(t,"array")||some(t=>Validation.interpret(i,t,e,o,r),Instance.iter(t));export default{id:id,compile:compile,interpret:interpret};